import React from 'react';
import styled from 'styled-components';

const Banner = styled.div`
  position: relative;
  width: 100%;
`;

const TitleContainer = styled.div`
  width: 60%;
`;

const Name = styled.p`
  text-align: center;
  font-size: 30pt;
  line-height: 46pt;
  position: relative;
  margin-bottom: .1in;
  width: 100%;
  border-bottom: solid 1px #000;

  @media (max-width: 900px) {
    font-size: 23pt;
    line-height: 35pt;
  }
  @media (max-width: 660px) {
    font-size: 15pt;
    line-height: 23pt;
  }
  @media print {
    font-size: 30pt;
    line-height: 46pt;
  }
`;

const ProfileStatement = styled.p`
  position: relative;
  font-size: 10pt;
  margin-bottom: .2in;

  @media (max-width: 900px) {
    font-size: 8pt;
    margin-bottom: .15in;
  }
  @media (max-width: 660px) {
    font-size: 5pt;
    margin-bottom: .1in;
  }
  @media print {
    font-size: 10pt;
    margin-bottom: .2in;
  }
`;

const ContactInfo = styled.div`
  position: absolute;
  top: 0%;
  right: 0%;
  width: 38%;
  text-align: left;
  font-size: 10pt;

  @media (max-width: 900px) {
    font-size: 7.5pt;
  }
  @media (max-width: 660px) {
    font-size: 5pt;
  }
  @media print {
    font-size: 10pt;
  }
`;

const ContactLabelBackdrop = styled.div`
  position: relative;
  display: inline-block;
  height: 100%;
  top: 0;
  left: 0;
  margin: 0;
  border-radius: 4px;
  box-shadow: inset 0 0 0 1000px #222;
`;

const ContactLabel = styled.img`
  display: block;
  margin: 5px;
  width: 26px;
  height: 26px;

  @media (max-width: 900px) {
    margin: 4px;
    width: 20px;
    height: 20px;
  }
  @media (max-width: 660px) {
    margin: 2.5px;
    width: 13px;
    height: 13px;
  }
  @media print {
    margin: 5px;
    width: 26px;
    height: 26px;
  }
`;

const ContactBackdrop = styled.div`
  position: absolute;
  display: inline-block;
  margin-left: 3px;

  @media (max-width: 900px) {
    margin-left: 2px;
  }
  @media (max-width: 660px) {
    margin-left: 2px;
  }
  @media print {
    margin-left: 3px;
  }
`;

const ContactPoint = styled.p`
  margin: 0;
  display: block;
  font-size: 10pt;
  line-height: 32px;

  @media (max-width: 900px) {
    font-size: 7.5pt;
    line-height: 25px;
  }
  @media (max-width: 660px) {
    font-size: 5pt;
    line-height: 16px;
  }
  @media print {
    font-size: 10pt;
    line-height: 32px;
  }
`;

const resumeContactLinks = (socialLinks) =>
  socialLinks.filter(link => link.displayText);

export const ResumeBanner = ({ personalInfo, socialLinks }) => {
  const contacts = resumeContactLinks(socialLinks);

  return (
    <Banner>
      <TitleContainer>
        <Name>{personalInfo.firstName} {personalInfo.lastName}</Name>
        <ProfileStatement>{personalInfo.profileStatement}</ProfileStatement>
      </TitleContainer>
      <ContactInfo>
        <ContactLabelBackdrop>
          {contacts.map(link => (
            <ContactLabel key={link.name} src={link.icon} alt={link.name} />
          ))}
        </ContactLabelBackdrop>
        <ContactBackdrop>
          {contacts.map(link => (
            <ContactPoint key={link.name}>{link.displayText}</ContactPoint>
          ))}
        </ContactBackdrop>
      </ContactInfo>
    </Banner>
  );
};
